function solve(nums: number[], queries: number[][]): number[] {
    const n = nums.length;
    const ans: number[] = [];

    // Preprocess the array to create a list of frequency maps for each index
    // We'll use a list of maps to store the frequency of each element in the subarray nums[0...i]
    const freqMaps: Map<number, Map<number, number>>[] = [];
    const freqMap = new Map<number, number>();
    freqMap.set(nums[0], 1);
    freqMaps.push(freqMap);

    // Build the frequency maps for each index
    for (let i = 1; i < n; i++) {
        const newFreqMap = new Map<number, number>(freqMaps[i - 1]);
        newFreqMap.set(nums[i], (newFreqMap.get(nums[i]) || 0) + 1);
        freqMaps.push(newFreqMap);
    }

    // Process each query
    for (const [li, ri, threshold] of queries) {
        // Get the frequency map for the subarray nums[li...ri]
        // We'll use a map to store the frequency of each element in the subarray
        const subFreq = new Map<number, number>();

        // For each element in the subarray, count its frequency
        for (let i = li; i <= ri; i++) {
            subFreq.set(nums[i], (subFreq.get(nums[i]) || 0) + 1);
        }

        // Find the element with the highest frequency that meets the threshold
        let maxFreq = -1;
        let result = -1;

        for (const [num, freq] of subFreq.entries()) {
            if (freq >= threshold && freq > maxFreq) {
                maxFreq = freq;
                result = num;
            } else if (freq >= threshold && freq === maxFreq) {
                result = Math.min(result, num);
            }
        }

        ans.push(result);
    }

    return ans;
}
